def extract_code_snippets(text):
  snippets = []

  def find_snippet(text: str, start_idx: int) -> str:
    opening_tag = "```"
    closing_tag = "```"

    opening_idx = text.find(opening_tag, start_idx)
    if opening_idx!= -1:
      closing_idx = text.find(closing_tag, opening_idx + len(opening_tag))
      if closing_idx!= -1:
        snippet = text[opening_idx + len(opening_tag): closing_idx].strip()
        return snippet, closing_idx + len(closing_tag)
      else:
        raise ValueError("Closing tag not found")
    else:
      return None, -1

  idx = 0
  while True:
    snippet, idx = find_snippet(text, idx)
    if snippet is None:
      break
    snippets.append(snippet)

  return snippets

