from typing import Any, Dict, List, Optional, Tuple

import torch
from transformers import BertTokenizerFast
from datasets import load_dataset

class DataLoader:
    def __init__(self, tokenizer: BertTokenizerFast):
        self._tokenizer = tokenizer

    @staticmethod
    def _tokenize_function(examples: Dict[str, Any]) -> Dict[str, Any]:

        tokenized_inputs = tokenizer(
            examples["source"], max_length=512, truncation=True, padding="max_length"
        )

        tokenized_labels = tokenizer(
            examples["target"], max_length=64, truncation=True, padding="max_length"
        )

        return {"input_ids": tokenized_inputs["input_ids"], "attention_mask": tokenized_inputs["attention_mask"],
                "decoder_input_ids": tokenized_labels["input_ids"], "decoder_attention_mask": tokenized_labels["attention_mask"]}

    def prepare_dataloader(self, dataset_path: str, batch_size: int, num_workers: int = 8) -> torch.utils.data.DataLoader:

        data = load_dataset("json", data_files=[f"{dataset_path}/train.jsonl"])

        tokenized_data = data.map(self._tokenize_function, batched=True, remove_columns=["source", "target"])

        train_dataloader = torch.utils.data.DataLoader(tokenized_data["train"], shuffle=True, batch_size=batch_size, num_workers=num_workers)

        return train_dataloader

