import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

/**
 * @author jack
 */
public class FileUtil {
  private static Path path = Paths.get("").toAbsolutePath();

  /**
   * Read file content by line
   *
   * @param fileName file name
   * @return file content
   */
  public static String readFileByLine(final String fileName) throws Exception {
    String result = StringUtils.EMPTY;
    final FileReader reader = new FileReader(path + "/" + fileName);
    final BufferedReader br = new BufferedReader(reader);
    String line;
    while ((line = br.readLine())!= null) {
      result += line;
    }
    br.close();
    reader.close();
    return result;
  }

  /**
   * Write file content
   *
   * @param fileName file name
   * @param content  file content
   */
  public static void writeFile(final String fileName, final String content) throws Exception {
    Files.write(path.resolve(fileName), content.getBytes());
  }
}

