from typing import Any, Dict, List, Optional, Union

def generate_prompt(
    instruction: str,
    context: str,
    question: str,
    answer: str,
    examples: Optional[List[Dict[str, str]]] = None,
    **kwargs: Any,
) -> str:
    """Generates a prompt based on the provided arguments."""
    if not isinstance(instruction, str):
        raise TypeError("`instruction` must be a string")
    if not isinstance(context, str):
        raise TypeError("`context` must be a string")
    if not isinstance(question, str):
        raise TypeError("`question` must be a string")
    if not isinstance(answer, str):
        raise TypeError("`answer` must be a string")
    if examples is not None and not all(isinstance(example, dict) for example in examples):
        raise TypeError("Each element in `examples` must be a dictionary")
    prompt = f"""{instruction}\n\nContext:\n{context}\n\nQuestion:\n{question}\n\nAnswer:\n"""
    if examples is not None:
        for example in examples:
            prompt += "\nExample:\n" + example["example"] + "\n\nExpected Output:\n" + example["output"] + "\n\n"
    prompt += answer
    return prompt
